// Extract node/entity type information from the HTML
const content = FILE_CONTENT;

// Look for graph node definitions, entity kinds, node types
const sections = [];

// Find any data structures defining node types
const entityMatches = content.match(/entity|node|kind|label|type/gi);

// Look for specific sections about nodes/entities
const lines = content.split('\n');
let inRelevantSection = false;
let relevantLines = [];

for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  // Look for node type definitions, graph entity references, entity kind enums
  if (line.match(/EntityKind|nodeType|node-type|entity-type|graph.*node|NODE_|ENTITY_/i) ||
      line.match(/class="node|data-node|data-entity|node-label/i) ||
      line.match(/'task'|'project'|'feature'|'decision'|'question'|'observation'|'person'|'policy'|'intent'/i)) {
    // Get surrounding context
    const start = Math.max(0, i - 2);
    const end = Math.min(lines.length - 1, i + 2);
    for (let j = start; j <= end; j++) {
      relevantLines.push(`L${j+1}: ${lines[j].trim()}`);
    }
    relevantLines.push('---');
  }
}

// Also look for any configuration objects or maps that define node properties
const configMatches = content.match(/(?:colors?|theme|config|styles?)\s*[=:]\s*\{[^}]*(?:task|project|feature|decision)[^}]*\}/gis);
if (configMatches) {
  sections.push('=== Config/Theme Objects ===');
  configMatches.forEach(m => sections.push(m.substring(0, 500)));
}

// Look for any comprehensive list/enum of entity types
const enumMatches = content.match(/(?:enum|const|type)\s+\w*(?:Entity|Node|Kind)\w*\s*[=:{][^;]*/gis);
if (enumMatches) {
  sections.push('=== Entity Enums/Types ===');
  enumMatches.forEach(m => sections.push(m.substring(0, 500)));
}

console.log('=== Relevant lines mentioning node/entity types ===');
// Deduplicate
const unique = [...new Set(relevantLines)];
console.log(unique.join('\n'));

console.log('\n' + sections.join('\n'));

const content = FILE_CONTENT;
const lines = content.split('\n');

// Find the section that describes graph nodes / the data model
// Look for headings and surrounding content about nodes, entities, graph structure
let results = [];

for (let i = 0; i < lines.length; i++) {
  const line = lines[i].trim();
  // Look for h2, h3, h4 headings that mention graph, nodes, entities, data model
  if (line.match(/<h[234][^>]*>.*(?:graph|node|entit|model|concept|feature|architec|how.*work|data|schema)/i)) {
    results.push(`\nL${i+1}: ${line}`);
    // Grab next 30 lines for context
    for (let j = i+1; j < Math.min(i+30, lines.length); j++) {
      results.push(`L${j+1}: ${lines[j].trim()}`);
    }
    results.push('---END SECTION---');
  }
}

// Also find section IDs
const sectionIds = [];
for (let i = 0; i < lines.length; i++) {
  if (lines[i].match(/id="[^"]*"/)) {
    const match = lines[i].match(/id="([^"]*)"/);
    if (match) sectionIds.push(`L${i+1}: id="${match[1]}" - ${lines[i].trim().substring(0, 100)}`);
  }
}

console.log('=== Section IDs ===');
console.log(sectionIds.join('\n'));
console.log('\n=== Relevant heading sections ===');
console.log(results.join('\n'));

